 1	import type { FC } from 'react';
 2	import useGetDeleteAndEditAccessReview from 'src/modules/Providers/hooks/useGetDeleteAndEditAccessReview';
 3	import { PageHeadings } from 'src/modules/Providers/utils/components/DetailsPage/PageHeadings';
 4	import { StorageMapActionsDropdown } from 'src/modules/StorageMaps/actions/StorageMapActionsDropdown';
 5	import StorageMapCriticalConditions from 'src/modules/StorageMaps/components/StorageMapCriticalConditions';
 6	
 7	import {
 8	  StorageMapModel,
 9	  StorageMapModelGroupVersionKind,
10	  type V1beta1StorageMap,
11	} from '@kubev2v/types';
12	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
13	import { PageSection } from '@patternfly/react-core';
14	import { CATEGORY_TYPES } from '@utils/constants';
15	import { isEmpty } from '@utils/helpers';
16	
17	export const StorageMapPageHeadings: FC<{ name: string; namespace: string }> = ({
18	  name,
19	  namespace,
20	}) => {
21	  const [obj, loaded, loadError] = useK8sWatchResource<V1beta1StorageMap>({
22	    groupVersionKind: StorageMapModelGroupVersionKind,
23	    name,
24	    namespace,
25	    namespaced: true,
26	  });
27	
28	  const permissions = useGetDeleteAndEditAccessReview({
29	    model: StorageMapModel,
30	    namespace,
31	  });
32	
33	  const alerts = [];
34	
35	  const criticalCondition =
36	    loaded &&
37	    !loadError &&
38	    obj?.status?.conditions?.find((condition) => condition?.category === CATEGORY_TYPES.CRITICAL);
39	
40	  if (criticalCondition) {
41	    alerts.push(
42	      <StorageMapCriticalConditions
43	        type={criticalCondition?.type}
44	        message={criticalCondition?.message ?? ''}
45	        key={'mapCriticalCondition'}
46	      />,
47	    );
48	  }
49	
50	  return (
51	    <>
52	      <PageHeadings
53	        model={StorageMapModel}
54	        obj={obj}
55	        namespace={namespace}
56	        actions={<StorageMapActionsDropdown data={{ obj, permissions }} fieldId={''} fields={[]} />}
57	      >
58	        {!isEmpty(alerts) && (
59	          <PageSection variant="light" className="forklift-page-headings-alerts">
60	            {alerts}
61	          </PageSection>
62	        )}
63	      </PageHeadings>
64	    </>
65	  );
66	};

